const $=(s,r=document)=>r.querySelector(s);const $$=(s,r=document)=>Array.from(r.querySelectorAll(s));
function show(el){if(el)el.style.display='block'}function hide(el){if(el)el.style.display='none'}
$$('.hamburger').forEach(btn=>btn.addEventListener('click',()=>{const menu=$('#mobile-menu');const open=!menu.classList.contains('open');menu.classList.toggle('open',open);btn.setAttribute('aria-expanded',String(open));}));
$$('.tab').forEach(tab=>tab.addEventListener('click',()=>{const root=tab.closest('.tool-card');$$('.tab',root).forEach(t=>t.setAttribute('aria-selected','false'));tab.setAttribute('aria-selected','true');$$('[data-panel]',root).forEach(p=>p.hidden=true);$(`[data-panel="${tab.dataset.tab}"]`,root).hidden=false;}));
$$('[data-start-check]').forEach(form=>form.addEventListener('submit',e=>{e.preventDefault();const consent=$('input[name="consent"]',form);const err=$('.error',form);const status=$('.status',form);hide(err);hide(status);if(!consent?.checked){err.textContent='CONSENT_REQUIRED: confirm that you have the right to upload or analyze this video/link before starting the preview.';show(err);return;}const selected=$('.tab[aria-selected="true"]',form)?.dataset.tab||'upload';const url=$('input[type="url"]',form)?.value.trim();if(selected==='url'&&!/^https:\/\//i.test(url)){err.textContent='INVALID_URL: enter a public https:// video link, or use the upload preview instead.';show(err);return;}status.textContent='Preview mode: creating a sample/manual checklist result. No real video analysis is running in this MVP preview.';show(status);setTimeout(()=>{location.href='/sample-report/?mode=manual_checklist';},650);}));
$$('[data-contact]').forEach(form=>form.addEventListener('submit',e=>{e.preventDefault();const status=$('.status',form);status.textContent='Preview contact form only: no message is sent yet while production email intake is being finalized.';show(status);}));
